/**
 * Types for sprite animation system.
 * Maps to sprite-atlas.json v1.4 generated by asset-generator.
 */

/* ──────────────────── sprite-atlas.json schema ──────────────────── */

/** Condition for row selection in grid layouts */
export interface AtlasCondition {
  readonly type: string;
  readonly value: string;
}

/** Row definition in a grid animation */
export interface AtlasRowDef {
  readonly rowIndex: number;
  readonly condition: AtlasCondition;
  readonly fps: number;
  readonly loop: boolean;
  readonly tint?: string;
  readonly opacity?: number;
}

/**
 * Crop offset — present when animation frames were cropped to their
 * non-transparent bounding box during generation.
 * Allows the frontend to position the cropped sprite correctly
 * within the original canvas coordinate space.
 */
export interface CropOffset {
  /** X offset of cropped region from original canvas top-left */
  readonly x: number;
  /** Y offset of cropped region from original canvas top-left */
  readonly y: number;
  /** Full uncropped canvas width */
  readonly originalWidth: number;
  /** Full uncropped canvas height */
  readonly originalHeight: number;
}

/** Single animation entry in sprite-atlas.json */
export interface AtlasAnimationEntry {
  readonly file: string;
  readonly layout: 'strip' | 'grid';
  readonly renderMode?: 'sprite' | 'overlay';
  readonly cropOffset?: CropOffset;
  readonly columns: number;
  readonly frameWidth: number;
  readonly frameHeight: number;
  readonly fps?: number;
  readonly loop?: boolean;
  readonly rows?: readonly AtlasRowDef[];
  readonly defaultRow?: number;
}

/** Root of sprite-atlas.json (v1.4 object format) */
export interface AtlasConfig {
  readonly configVersion: string;
  readonly revision: string;
  readonly entity: string;
  readonly character?: string;
  /**
   * Display scale from atlas config.
   * DEPRECATED for sizing — kept for backward compat.
   * Use sceneRelativeHeight for actual sizing.
   */
  readonly displayScale?: number;
  readonly animations: Record<string, AtlasAnimationEntry>;
}

/* ──────────────────── Resolved runtime types ──────────────────── */

/** Resolved animation ready for rendering */
export interface SpriteAnimation {
  readonly name: string;
  readonly atlasUrl: string;
  readonly frameWidth: number;
  readonly frameHeight: number;
  readonly frameCount: number;
  readonly fps: number;
  readonly loop: boolean;
  readonly layout: 'strip' | 'grid';
  readonly renderMode: 'sprite' | 'overlay';
  readonly totalRows: number;
  readonly currentRow: number;
  /** @deprecated Use sceneRelativeHeight instead */
  readonly displayScale: number;
  /** Crop offset if frames were cropped during generation */
  readonly cropOffset?: CropOffset;
  readonly tint?: string;
  readonly opacity?: number;
}

/** Props for SpriteAnimator component */
export interface SpriteAnimatorProps {
  readonly entityType: string;
  readonly entityName: string;
  readonly animation: string;
  /**
   * Optional multiplier ON TOP of relative sizing.
   * Default: 1.0 (use relative size as-is).
   */
  readonly scale?: number | undefined;
  /**
   * Fraction of SCENE_HEIGHT this sprite should occupy (0..1).
   * e.g. 0.40 = 40% of viewport height.
   * If omitted, sprite renders at native frame size (1:1 in scene).
   *
   * Explicitly allows `undefined` for compatibility with
   * exactOptionalPropertyTypes (TS2375).
   */
  readonly sceneRelativeHeight?: number | undefined;
  readonly playing?: boolean | undefined;
  readonly className?: string | undefined;
  readonly onComplete?: (() => void) | undefined;
  readonly condition?: string | undefined;
}

/** State of the sprite animation hook */
export interface SpriteAnimationState {
  readonly currentFrame: number;
  readonly isLoaded: boolean;
  readonly isPlaying: boolean;
  readonly error: string | null;
  readonly animation: SpriteAnimation | null;
}
